 1	import React, { FC } from 'react';
 2	
 3	import { useModal } from '@kubevirt-utils/components/ModalProvider/ModalProvider';
 4	import SSHSecretModal from '@kubevirt-utils/components/SSHSecretModal/SSHSecretModal';
 5	import { initialSSHCredentials } from '@kubevirt-utils/components/SSHSecretModal/utils/constants';
 6	import {
 7	  SecretSelectionOption,
 8	  SSHSecretDetails,
 9	} from '@kubevirt-utils/components/SSHSecretModal/utils/types';
10	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
11	import { isEmpty } from '@kubevirt-utils/utils/utils';
12	import { Button } from '@patternfly/react-core';
13	import { PencilAltIcon } from '@patternfly/react-icons';
14	
15	type AddProjectAuthKeyButtonProps = {
16	  onSubmit: (sshDetails: SSHSecretDetails) => Promise<any>;
17	  secretName: string;
18	  selectedProject: string;
19	};
20	
21	const AddProjectAuthKeyButton: FC<AddProjectAuthKeyButtonProps> = ({
22	  onSubmit,
23	  secretName,
24	  selectedProject,
25	}) => {
26	  const { t } = useKubevirtTranslation();
27	
28	  const { createModal } = useModal();
29	  return (
30	    <Button
31	      onClick={() =>
32	        createModal((modalProps) => (
33	          <SSHSecretModal
34	            initialSSHSecretDetails={
35	              isEmpty(secretName)
36	                ? initialSSHCredentials
37	                : {
38	                    applyKeyToProject: true,
39	                    secretOption: SecretSelectionOption.useExisting,
40	                    sshPubKey: '',
41	                    sshSecretName: secretName,
42	                    sshSecretNamespace: selectedProject,
43	                  }
44	            }
45	            namespace={selectedProject}
46	            onSubmit={onSubmit}
47	            {...modalProps}
48	            isUserTab
49	          />
50	        ))
51	      }
52	      className="project-ssh-row__secret-name"
53	      isDisabled={isEmpty(selectedProject)}
54	      isInline
55	      variant="link"
56	    >
57	      {isEmpty(secretName) ? t('Not configured') : secretName}{' '}
58	      <PencilAltIcon className="co-icon-space-l pf-v6-c-button-icon--plain" />
59	    </Button>
60	  );
61	};
62	
63	export default AddProjectAuthKeyButton;

